// // This module implements a two-input OR-AND-Invert (OAI22) logic gate with a drive strength of 2x. It provides a logic low output only when both pairs of its inputs are not simultaneously logic high.
module bw_u1_oai22_2x (
    z,
    a1,
    a2,
    b1,
    b2 );
    output z;
    input  a1;
    input  a2;
    input  b1;
    input  b2;
    assign z = ~(( a1 | a2 ) & ( b1 | b2 ));
endmodule
